#include "sda_interval.h"
#include <assert.h>
int main(void){ mpfr_t a,b,v; mpfr_inits2(256,a,b,v,(mpfr_ptr)0); sda_mpfr_interval x,y,z; sda_interval_init(&x,256); sda_interval_init(&y,256); sda_interval_init(&z,256); mpfr_set_d(a,1.25,MPFR_RNDN); mpfr_set_d(b,2.5,MPFR_RNDN); sda_interval_set(&x,a); sda_interval_set(&y,b); sda_interval_add(&z,&x,&y); mpfr_set_d(v,3.75,MPFR_RNDN); assert(sda_interval_contains(&z,v)); sda_interval_sub(&z,&y,&x); mpfr_set_d(v,1.25,MPFR_RNDN); assert(sda_interval_contains(&z,v)); sda_interval_mul(&z,&x,&y); mpfr_set_d(v,3.125,MPFR_RNDN); assert(sda_interval_contains(&z,v)); sda_interval_div(&z,&y,&x); mpfr_set_d(v,2.0,MPFR_RNDN); assert(sda_interval_contains(&z,v)); mpfr_set_d(a,-1.5,MPFR_RNDN); mpfr_set_d(b,0.25,MPFR_RNDN); sda_interval_set(&x,a); sda_interval_set(&y,b); sda_interval_abs(&z,&x); mpfr_set_d(v,1.5,MPFR_RNDN); assert(sda_interval_contains(&z,v)); sda_interval_max(&z,&x,&y); mpfr_set_d(v,0.25,MPFR_RNDN); assert(sda_interval_contains(&z,v)); sda_interval_clear(&x); sda_interval_clear(&y); sda_interval_clear(&z); mpfr_clears(a,b,v,(mpfr_ptr)0); return 0; }
